  KEY `idx_ai_inference_fuseki_pending` (`fuseki_graph_uri`(1),`created_at`),
  KEY `idx_ai_inference_user` (`user_id`,`occurred_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
