DROP TABLE IF EXISTS `ahg_ai_override`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE IF NOT EXISTS `ahg_ai_override` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `uuid` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'External-facing identifier; used as the override activity URI in Fuseki',
  `inference_id` bigint unsigned NOT NULL COMMENT 'FK to ahg_ai_inference - the inference being corrected',
  `reviewer_user_id` int NOT NULL COMMENT 'User who issued the correction',
  `reason` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Free-text rationale; nullable but encouraged',
  `original_value` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Snapshot of what the AI produced (for the trace, even though it is also derivable from the inference row)',
  `override_value` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'What the reviewer set the field to',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'applied' COMMENT 'applied, rejected, superseded - lifecycle of the correction',
  `fuseki_override_uri` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'NULL until the prov:Activity has been written to Fuseki',
  `occurred_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_ai_override_uuid` (`uuid`),
  KEY `idx_ai_override_inference` (`inference_id`),
  KEY `idx_ai_override_reviewer` (`reviewer_user_id`,`occurred_at`),
  KEY `idx_ai_override_status` (`status`,`occurred_at`),
  KEY `idx_ai_override_fuseki_pending` (`fuseki_override_uri`(1),`created_at`),
  CONSTRAINT `fk_ai_override_inference` FOREIGN KEY (`inference_id`) REFERENCES `ahg_ai_inference` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

