DROP TABLE IF EXISTS `ahg_mention_context`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE IF NOT EXISTS `ahg_mention_context` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `mention_id` bigint unsigned NOT NULL,
  `character_offset_start` int unsigned DEFAULT NULL,
  `character_offset_end` int unsigned DEFAULT NULL,
  `paragraph_offset_start` int unsigned DEFAULT NULL,
  `paragraph_offset_end` int unsigned DEFAULT NULL,
  `surrounding_text_before` text COLLATE utf8mb4_unicode_ci COMMENT 'up to 150 chars before mention',
  `surrounding_text_after` text COLLATE utf8mb4_unicode_ci COMMENT 'up to 150 chars after mention',
  `ner_model_version` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `real_confidence` decimal(6,4) DEFAULT NULL COMMENT 'NULL until upstream API exposes per-entity scores',
  `co_occurring_entities` json DEFAULT NULL COMMENT 'Array of {ner_entity_id?, value, type, distance_tokens}',
  `nearby_dates` json DEFAULT NULL COMMENT 'Array of {value, normalized?, distance_tokens}',
  `nearby_places` json DEFAULT NULL COMMENT 'Array of {value, term_id?, distance_tokens}',
  `role_language_tokens` json DEFAULT NULL COMMENT 'Array of {token, position_offset, kind: kinship|witness|location|movement|other}',
  `computed_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_context_mention` (`mention_id`),
  CONSTRAINT `fk_context_mention` FOREIGN KEY (`mention_id`) REFERENCES `ahg_mention` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

