  `evidence_snapshot` json DEFAULT NULL COMMENT 'Frozen copy of evidence_signals + evidence_data shown at decision time',
  `candidates_visible_snapshot` json DEFAULT NULL COMMENT 'Array of {candidate_id, display_name, rank} visible at decision',
  PRIMARY KEY (`id`),
  KEY `idx_decision_mention` (`mention_id`,`decided_at`),
  KEY `idx_decision_archivist` (`archivist_user_id`,`decided_at`),
  KEY `fk_decision_candidate` (`chosen_candidate_id`),
  CONSTRAINT `fk_decision_candidate` FOREIGN KEY (`chosen_candidate_id`) REFERENCES `ahg_mention_candidate` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_decision_mention` FOREIGN KEY (`mention_id`) REFERENCES `ahg_mention` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

